WITH gmail_users AS (
  SELECT customer_id FROM customers WHERE email LIKE '%@gmail.com'
),
high_value AS (
  SELECT DISTINCT customer_id FROM orders WHERE total_amount > 300
)
SELECT c.* FROM customers c WHERE c.customer_id IN (SELECT customer_id FROM gmail_users) AND c.customer_id IN (SELECT customer_id FROM high_value);

WITH old_hires AS (
  SELECT emp_id FROM employees WHERE hire_date < '2021-01-01'
),
marketing AS (
  SELECT emp_id FROM employees WHERE department = 'Marketing'
)
SELECT e.* FROM employees e WHERE e.emp_id IN (SELECT emp_id FROM old_hires) AND e.emp_id IN (SELECT emp_id FROM marketing);

WITH usa_customers AS (
  SELECT customer_id FROM customers WHERE country = 'USA'
),
recent_high_spenders AS (
  SELECT customer_id FROM orders WHERE order_date > '2024-01-01' GROUP BY customer_id HAVING SUM(total_amount) > 500
)
SELECT c.* FROM customers c WHERE c.customer_id IN (SELECT customer_id FROM usa_customers) AND c.customer_id IN (SELECT customer_id FROM recent_high_spenders);

WITH surgeons AS (
  SELECT * FROM doctors WHERE department = 'Surgery'
)
SELECT * FROM surgeons;

WITH econ_students AS (
  SELECT * FROM students WHERE major = 'Economics'
)
SELECT * FROM econ_students;

WITH completed_orders AS (
  SELECT DISTINCT customer_id FROM orders WHERE status = 'completed'
)
SELECT c.* FROM customers c WHERE c.customer_id IN (SELECT customer_id FROM completed_orders);

